// src/History.jsx
import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

const apiBase = "https://prasa-app-yde3.onrender.com"; // backend URL
const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function History({ employee }) {
  const [travelExpenses, setTravelExpenses] = useState([]);
  const [ticketExpenses, setTicketExpenses] = useState([]);
  const [bills, setBills] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    if (employee?.empld) {
      fetchData();
    }
  }, [employee]);

  const fetchData = async () => {
    try {
      const [tRes, kRes, bRes] = await Promise.all([
        fetch(
          `${apiBase}/travel-expenses?empld=${encodeURIComponent(
            employee.empld
          )}`
        ),
        fetch(
          `${apiBase}/ticket-expenses?empld=${encodeURIComponent(
            employee.empld
          )}`
        ),
        fetch(`${apiBase}/bills?empld=${encodeURIComponent(employee.empld)}`),
      ]);

      const [travel, tickets, billsData] = await Promise.all([
        tRes.json(),
        kRes.json(),
        bRes.json(),
      ]);

      setTravelExpenses(travel || []);
      setTicketExpenses(tickets || []);
      setBills(Array.isArray(billsData) ? billsData : []);
    } catch (err) {
      console.error("History fetch error:", err);
    }
  };

  return (
    <div
      style={{
        minHeight: "100vh",
        background: lightGreen,
        padding: 16,
        fontFamily: "Segoe UI",
      }}
    >
      <div
        style={{
          maxWidth: 950,
          margin: "0 auto",
          background: "#ffffff",
          borderRadius: 16,
          padding: 18,
          boxShadow: "0 6px 20px rgba(0,0,0,0.12)",
        }}
      >
        {/* Back arrow + title */}
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: 10,
            marginBottom: 8,
          }}
        >
          <button
            onClick={() => navigate("/profile")}
            style={{
              background: "transparent",
              border: "none",
              color: green,
              fontSize: 16,
              cursor: "pointer",
            }}
          >
            ⬅ Back
          </button>
          <h2 style={{ color: green, margin: 0 }}>History</h2>
        </div>

        <p style={{ fontSize: 13, color: "#555" }}>
          Employee: {employee.name} • {employee.empld}
        </p>

        {/* Travel History */}
        <h3 style={{ color: green, marginTop: 16 }}>Travel Expense History</h3>
        <table style={tableStyle()}>
          <thead>
            <tr>
              <th>Date</th>
              <th>Purpose</th>
              <th>Amount</th>
              <th>From</th>
              <th>To</th>
            </tr>
          </thead>
          <tbody>
            {travelExpenses.map((t) => (
              <tr key={t.id}>
                <td>{t.travel_date?.split?.("T")?.[0] || t.travel_date}</td>
                <td>{t.purpose}</td>
                <td>₹{t.amount}</td>
                <td>{t.location_from}</td>
                <td>{t.location_to}</td>
              </tr>
            ))}
            {travelExpenses.length === 0 && (
              <tr>
                <td colSpan="5" style={{ textAlign: "center", padding: 10 }}>
                  No travel records yet.
                </td>
              </tr>
            )}
          </tbody>
        </table>

        {/* Ticket History */}
        <h3 style={{ color: green, marginTop: 20 }}>Ticket Expense History</h3>
        <table style={tableStyle()}>
          <thead>
            <tr>
              <th>Date</th>
              <th>Purpose</th>
              <th>Assigned To</th>
              <th>Amount</th>
            </tr>
          </thead>
          <tbody>
            {ticketExpenses.map((t) => (
              <tr key={t.id}>
                <td>{t.ticket_date?.split?.("T")?.[0] || t.ticket_date}</td>
                <td>{t.purpose}</td>
                <td>{t.assigned_to}</td>
                <td>₹{t.amount}</td>
              </tr>
            ))}
            {ticketExpenses.length === 0 && (
              <tr>
                <td colSpan="4" style={{ textAlign: "center", padding: 10 }}>
                  No ticket records yet.
                </td>
              </tr>
            )}
          </tbody>
        </table>

        {/* Bills History */}
        <h3 style={{ color: green, marginTop: 20 }}>Bills Upload History</h3>
        <table style={tableStyle()}>
          <thead>
            <tr>
              <th>Date</th>
              <th>File Name</th>
              <th>Preview</th>
            </tr>
          </thead>
          <tbody>
            {bills.map((b) => (
              <tr key={b.id}>
                <td>{b.created_at?.split?.("T")?.[0] || b.created_at}</td>
                <td>{b.fileName || b.filename}</td>
                <td>
                  {b.filePath && (
                    <a
                      href={`${apiBase}${b.filePath}`}
                      target="_blank"
                      rel="noreferrer"
                    >
                      Open
                    </a>
                  )}
                </td>
              </tr>
            ))}
            {bills.length === 0 && (
              <tr>
                <td colSpan="3" style={{ textAlign: "center", padding: 10 }}>
                  No bills uploaded yet.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function tableStyle() {
  return {
    width: "100%",
    borderCollapse: "collapse",
    fontSize: 13,
  };
}
